DDL:
DROP TABLE IF EXISTS DIM_STATE CASCADE;
CREATE TABLE DIM_STATE (
	STATE_ID BIGINT PRIMARY KEY,
	STATE_NAME VARCHAR(50)
);

DROP TABLE IF EXISTS DIM_DISTRICT CASCADE;
CREATE TABLE DIM_DISTRICT (
	DISTRICT_ID BIGINT PRIMARY KEY,
	STATE_ID BIGINT,
	DISTRICT_NAME VARCHAR(50),
	FOREIGN KEY (STATE_ID) REFERENCES DIM_STATE (STATE_ID)
);

DROP TABLE IF EXISTS DIM_PSU_VILLAGE CASCADE;
CREATE TABLE DIM_PSU_VILLAGE (
	PSU_VILLAGE_ID BIGINT PRIMARY KEY,
	DISTRICT_ID BIGINT,
	PSU_VILLAGE_CODE BIGINT,
	FOREIGN KEY (DISTRICT_ID) REFERENCES DIM_DISTRICT (DISTRICT_ID)
);

DROP TABLE IF EXISTS DIM_HOUSEHOLD CASCADE;
CREATE TABLE DIM_HOUSEHOLD (
	HOUSEHOLD_ID BIGINT PRIMARY KEY,
	PSU_VILLAGE_ID BIGINT,
	HOUSEHOLD_ID_ORIGINAL BIGINT,
	SPLIT_HOUSEHOLD_ID BIGINT,
	FOREIGN KEY (PSU_VILLAGE_ID) REFERENCES DIM_PSU_VILLAGE (PSU_VILLAGE_ID)
);

DROP TABLE IF EXISTS DIM_MOTHER_DEMOGRAPHICS CASCADE;
CREATE TABLE DIM_MOTHER_DEMOGRAPHICS (
	MOTHER_ID BIGINT PRIMARY KEY,
	MOTHER_DATE_OF_BIRTH_IMPUTED_CMC VARCHAR(50),
	MOTHER_DATE_OF_BIRTH_FLAG VARCHAR(50),
	MOTHER_AGE_IMPUTED BIGINT
);

DROP TABLE IF EXISTS DIM_CHILD_DEMOGRAPHICS CASCADE;
CREATE TABLE DIM_CHILD_DEMOGRAPHICS (
	CHILD_ID BIGINT PRIMARY KEY,
	CHILD_SEX VARCHAR(20),
	CHILD_DATE_OF_BIRTH_IMPUTED_CMC VARCHAR(50),
	CHILD_DATE_OF_BIRTH_FLAG VARCHAR(50),
	CHILD_AGE_AT_DEATH_IMPUTED VARCHAR(20),
	CHILD_AGE_AT_DEATH_FLAG VARCHAR(50),
	CHILD_LIVING_STATUS VARCHAR(50)
);

DROP TABLE IF EXISTS DIM_SURVEY CASCADE;
CREATE TABLE DIM_SURVEY (
	SURVEY_ID BIGINT PRIMARY KEY,
	INTERVIEW_DATE_IMPUTED_CMC VARCHAR(50)
);
